### 1. DOMAIN MODEL (Source of Truth)

**File:** `/c/Users/johnm/modular apartment planner/src/domain/models.js`

**Window object:**
```javascript
{
  id: "win_<timestamp>_<counter>",
  wallId: "<wall_id>",
  offset: <number>,           // Position along wall in mm
  width: 1200,                // Default from WINDOW_WIDTH
  height: 1200,               // From WINDOW_HEIGHT
  sillHeight: 900,            // From WINDOW_SILL_HEIGHT
  type: "standard",           // Window type (extensible)
  openDirection: "left"       // left | right
}
```

**Door object:**
```javascript
{
  id: "door_<timestamp>_<counter>",
  wallId: "<wall_id>",
  offset: <number>,           // Position along wall in mm
  width: 900,                 // Default from DOOR_WIDTH
  height: 2100,               // From DOOR_HEIGHT
  sillHeight: 0,              // From DOOR_SILL_HEIGHT
  openDirection: "left",      // left | right
  type: "swing"               // swing | double | sliding | pocket | bifold
}
```

**Default values:** `/c/Users/johnm/modular apartment planner/src/domain/defaults.js`
- `WINDOW_WIDTH = 1200mm`, `WINDOW_HEIGHT = 1200mm`, `WINDOW_SILL_HEIGHT = 900mm`
- `DOOR_WIDTH = 900mm`, `DOOR_HEIGHT = 2100mm`, `DOOR_SILL_HEIGHT = 0mm`

---

### 2. WALL PREVIEW CONTEXT (Position Calculation)

**File:** `/c/Users/johnm/modular apartment planner/src/three/scene/wallPreviewContext.js`

The system builds `wallPreviewContext` objects that contain opening descriptors with calculated positions. Key function:

```javascript
function buildOpeningDescriptor(kind, source, context) {
  // Maps door/window model → wall-relative coordinates
  // Handles clipping to visible portion of wall

  return {
    id: source.id,
    kind: "door" | "window",
    wallId: context.wall.id,
    sourceId: source.id,
    angle: wallAngle(context.renderWall),
    wallThickness: context.renderWall.thickness,
    width: source.width,
    height: source.height ?? 0,
    sillHeight: source.sillHeight ?? 0,
    startAlong, endAlong, centerAlong,          // Positions along wall length
    visibleWidth, visibleHeight,                // Clipped to visible wall section
    visibleBaseElevation, visibleTopElevation,  // Elevation range
    startPoint, endPoint, centerPoint,          // World coordinates
    outline: wallOutline(...),                  // 2D footprint
    metadata: { wallId, floorId, sourceStart/EndAlong, clipped... }
  };
}
```

This context flows through `buildWallPreviewContexts()` which processes all doors and windows per wall.

---

### 3. OBJECT BUILDERS (Descriptor Generation)

**File:** `/c/Users/johnm/modular apartment planner/src/three/scene/objectBuilders.js`

**Key functions:**

#### `buildWindowObjects(wallContexts)`
```javascript
function buildWindowObjects(wallContexts) {
  return wallContexts
    .flatMap((context) => context.openings)
    .filter((opening) => opening.kind === 'window')
    .map((opening) => createOpeningInsertDescriptor(opening));
}
```

#### `buildDoorObjects(wallContexts)`
```javascript
function buildDoorObjects(wallContexts) {
  return wallContexts
    .flatMap((context) => context.openings)
    .filter((opening) => opening.kind === 'door')
    .map((opening) => createOpeningInsertDescriptor(opening));
}
```

Both use the same descriptor builder:

#### `createOpeningInsertDescriptor(opening)` - CRITICAL FUNCTION
```javascript
function createOpeningInsertDescriptor(opening) {
  return createBoxDescriptor(
    opening.id,
    opening.kind,                               // "door" or "window"
    opening.centerPoint,                        // XY position on wall
    {
      x: opening.visibleWidth,                  // Width of visible opening
      y: opening.visibleHeight,                 // Height of visible opening
      z: getInsertThickness(opening.kind, opening.wallThickness),  // Thickness
    },
    opening.visibleBaseElevation,               // Elevation in world space
    opening.angle,                              // Rotation angle
    {
      sourceId: opening.sourceId,
      floorId: opening.metadata.floorId,
      wallId: opening.wallId,
      openingKind: opening.kind,                // Metadata preserves door/window type
    }
  );
}
```

#### `getInsertThickness(kind, wallThickness)` - THICKNESS LOGIC
```javascript
function getInsertThickness(kind, wallThickness) {
  if (kind === 'door') {
    return Math.max(
      DOOR_INSERT_THICKNESS_MIN,                // 35mm
      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)  // 35-70mm
    );
  }

  return Math.max(
    WINDOW_INSERT_THICKNESS_MIN,                // 45mm
    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)  // 45-90mm
  );
}
```

**Key insight:** Door/window thickness scales with wall thickness:
- **Doors:** 22% of wall thickness, clamped 35-70mm
- **Windows:** 32% of wall thickness, clamped 45-90mm

#### `createBoxDescriptor(id, kind, center, size, baseElevation, rotation, metadata)`
Creates a box geometry descriptor with:
- `geometry: 'box'`
- `kind: 'door' | 'window'`
- `materialKey: 'door' | 'window'` (used for material lookup)
- `metadata.openingKind` - preserves the door/window type from the source object

The descriptor hierarchy for final 3D scene:
```javascript
export function buildFloorPreviewObjects(floor) {
  const wallContexts = buildWallPreviewContexts(floor, floorLevel);

  return [
    ...buildSlabObjects(floor),
    ...buildWallObjects(wallContexts),
    ...buildColumnObjects(floor, floorLevel),
    ...buildBeamObjects(floor),
    ...buildStairObjects(floor, floorLevel),
    ...buildDoorObjects(wallContexts),      // Returns box descriptors
    ...buildWindowObjects(wallContexts),    // Returns box descriptors
  ];
}
```

---

### 4. MATERIAL PALETTE

**File:** `/c/Users/johnm/modular apartment planner/src/three/viewer/materials.js`

```javascript
{
  door: new THREE.MeshStandardMaterial({
    color: 0xc48f5d,           // Warm brown/tan
    roughness: 0.82,
    metalness: 0.04,
    side: THREE.DoubleSide,
  }),

  window: new THREE.MeshStandardMaterial({
    color: 0x8dc8ef,           // Light blue (glass)
    roughness: 0.15,           // Very smooth/reflective
    metalness: 0.02,
    transparent: true,
    opacity: 0.48,             // 48% transparency for glass effect
    side: THREE.DoubleSide,
  }),

  // Other materials: wall, slab, column, beam, stair, outline
}
```

**Material assignment:** Uses `descriptor.materialKey` which is set to `descriptor.kind` (`'door'` or `'window'`)

---

### 5. THREE.JS MESH CREATION

**File:** `/c/Users/johnm/modular apartment planner/src/three/viewer/buildPreviewObjects.js`

#### `buildPreviewObjectRoot(sceneDescriptor, materialPalette)`

```javascript
export function buildPreviewObjectRoot(sceneDescriptor, materialPalette) {
  const root = new THREE.Group();

  for (const floor of sceneDescriptor.floors) {
    const floorGroup = new THREE.Group();
    floorGroup.name = `floor-${floor.floorId}`;

    for (const descriptor of floor.objects) {
      const object = createObjectForDescriptor(descriptor, materialPalette);
      object.name = descriptor.id;
      object.userData = {
        id: descriptor.id,
        kind: descriptor.kind,                  // 'door' or 'window'
        metadata: descriptor.metadata,
      };
      floorGroup.add(object);
    }

    root.add(floorGroup);
  }

  return root;
}
```

#### `createObjectForDescriptor(descriptor, materialPalette)`

```javascript
function createObjectForDescriptor(descriptor, materialPalette) {
  if (descriptor.geometry === 'prism') {
    return createPrismObject(descriptor, materialPalette);
  }

  if (descriptor.geometry === 'stair') {
    return createStairObject(descriptor, materialPalette);
  }

  return createBoxObject(descriptor, materialPalette);  // Door & window path
}
```

#### `createBoxObject(descriptor, materialPalette)` - DOOR/WINDOW CREATION

```javascript
function createBoxObject(descriptor, materialPalette) {
  // Create raw Three.js box geometry
  const geometry = new THREE.BoxGeometry(
    Math.max(descriptor.size.x, 1),   // Width (along wall)
    Math.max(descriptor.size.y, 1),   // Height (vertical)
    Math.max(descriptor.size.z, 1)    // Thickness (into wall)
  );

  // Apply material from palette by materialKey ('door' or 'window')
  const mesh = new THREE.Mesh(geometry, materialPalette[descriptor.materialKey]);

  // Position: center point + half height in world space
  const center = planPointToWorld(
    descriptor.center,
    descriptor.baseElevation + descriptor.size.y / 2
  );
  mesh.position.copy(center);

  // Rotation around Y axis (vertical)
  mesh.rotation.y = planAngleToWorldRotation(descriptor.rotation);

  mesh.castShadow = true;
  mesh.receiveShadow = true;

  // Add edge outline
  addOutline(mesh, materialPalette);

  return mesh;
}
```

#### `addOutline(object3d, materialPalette)`

```javascript
function addOutline(object3d, materialPalette) {
  if (!object3d.geometry) return;
  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);  // 20° threshold
  const outline = new THREE.LineSegments(edges, materialPalette.outline);
  object3d.add(outline);
}
```

---

### 6. COORDINATE TRANSFORMATION PIPELINE

**Key functions from `buildPreviewObjects.js`:**

```javascript
function planPointToWorld(point, elevation = 0) {
  // Plan coords (X, Y in mm) → World coords (X, Y, Z in Three.js)
  return new THREE.Vector3(point.x, elevation, point.y);
}

function planAngleToWorldRotation(angle = 0) {
  // Wall angle → Three.js Y-axis rotation
  return -angle;  // Negated for proper handedness
}
```

**Elevation system:**
- Model space: Y = vertical elevation (mm)
- Three.js space: Y = vertical (world up), X = plan X, Z = plan Y
- `baseElevation` from descriptor → mesh Y position
- Mesh height centers at `baseElevation + size.y / 2`

---

### 7. SVG DOOR RENDERING (Pattern Reference)

**File:** `/c/Users/johnm/modular apartment planner/src/renderers/DoorRenderer.jsx`

Shows supported door types via SVG:
- **`swing`** - Single hinged door with arc showing swing direction
- **`double`** - Two hinged leaves that meet in center
- **`sliding`** - Horizontal line with directional arrow (thickness 4px)

Window types mentioned in domain model suggest extensibility, but currently only visual difference is in SVG preview. The 3D preview renders both doors and windows as simple boxes with no type-specific geometry differentiation in `buildPreviewObjects.js`.

---

### 8. SCENE ASSEMBLY ORCHESTRATION

**File:** `/c/Users/johnm/modular apartment planner/src/three/scene/buildPreviewScene.js`

```javascript
export function buildPreviewScene(project, options = {}) {
  const floors = project?.floors || [];
  const activeFloorId = options.activeFloorId ?? floors[0]?.id ?? null;

  const floorDescriptors = floors.map((floor) => {
    const objects = buildFloorPreviewObjects(floor);  // Gets all descriptors
    return {
      floorId: floor.id,
      name: floor.name,
      level: floor.level ?? 0,
      visible: visibleFloorIds.has(floor.id),
      objects,                                        // Contains door/window descriptors
      bounds: boundsFromObjects(objects),             // Calc camera bounds
    };
  });

  return {
    activeFloorId,
    visibleFloorIds: [...visibleFloorIds],
    floors: floorDescriptors,
    bounds,                                           // Used for camera fitting
    defaultTarget: { x, y, z },
    groundLevel,
    hasVisibleObjects,
  };
}
```

---

### 9. REACT INTEGRATION

**File:** `/c/Users/johnm/modular apartment planner/src/three/viewer/ThreePreviewPanel.jsx`

```javascript
export default function ThreePreviewPanel({ project, activeFloorId, className = '' }) {
  // 1. Build scene descriptor (calls buildFloorPreviewObjects → windows & doors included)
  const sceneDescriptor = useMemo(() => buildPreviewScene(project, {
    activeFloorId,
    visibleFloorIds: activeFloorId ? [activeFloorId] : [],
  }), [project, activeFloorId]);

  // 2. Create Three.js viewport
  useEffect(() => {
    const viewport = createPreviewViewport(containerRef.current);
    // ... setup
  }, []);

  // 3. Build Three.js objects and render
  useEffect(() => {
    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette);
    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
  }, [sceneDescriptor]);

  return <section>3D preview canvas</section>;
}
```

---

### Summary: Key Pipeline

```
Domain Model (window/door object)
         ↓
Wall Preview Context (position calculation on wall)
         ↓
Object Descriptor (createOpeningInsertDescriptor)
  - kind: 'door' | 'window'
  - geometry: 'box'
  - materialKey: 'door' | 'window'
  - size: { x: visibleWidth, y: visibleHeight, z: thickness }
  - baseElevation, angle, rotation
         ↓
Scene Descriptor (buildPreviewScene)
         ↓
Three.js Objects (createBoxObject)
  - THREE.BoxGeometry
  - THREE.Mesh with palette material
  - THREE.EdgesGeometry for outlines
  - Shadow casting enabled
         ↓
Floor Groups (buildPreviewObjectRoot)
         ↓
Three.js Scene (createPreviewViewport)
  - WebGL Renderer
  - Orbit Controls
  - Lighting (Ambient + Hemisphere + Directional)
  - Grid Helper
```

---

### Critical Details for Extension

1. **Door/window type is preserved in `metadata.openingKind`** but currently unused in 3D rendering
2. **Thickness calculation scales with wall:** `getInsertThickness()` - doors at 22%, windows at 32% of wall thickness
3. **Material assignment is type-based:** All doors use one material, all windows another - no type-specific differentiation
4. **Doors have rich SVG types** (swing/double/sliding) that could be expanded to 3D with type-specific geometry in `createBoxObject()`
5. **All geometry currently uses box shapes** - could be enhanced to draw geometry based on `descriptor.metadata.openingKind` (e.g., swing doors could show hinge geometry)
6. **Rotation and elevation are fully supported** - positioned on correct walls and heights automatically
